#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long x,y,K,N; scanf("%lld %lld %lld %lld", &x, &y, &K, &N);
        long long d = llabs(x - y);
        if (d % (2LL * K) == 0) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

